[.github/workflows/prompt-regression-test.yml]

name: Prompt Regression Test

on:
  pull_request:
    paths:
      - 'prompts/'
      - 'eval_dataset.json'
  push:
    branches:
      - main
    paths:
      - 'prompts/'

jobs:
  eval:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v3

      - name: Setup Node.js
        uses: actions/setup-node@v3
        with:
          node-version: '18'

      - name: Install Promptfoo
        run: npm install -g promptfoo

      - name: Run Eval
        env:
          ANTHROPIC_API_KEY: ${{ secrets.ANTHROPIC_API_KEY }}
        run: promptfoo eval --config promptfooconfig.yaml --output eval_results.json

      - name: Check Thresholds
        run: |
          node scripts/check_thresholds.js eval_results.json

      - name: Post Results to PR
        if: github.event_name == 'pull_request'
        uses: actions/github-script@v6
        with:
          script: |
            const fs = require('fs');
            const results = JSON.parse(fs.readFileSync('eval_results.json', 'utf8'));
            const comment = ## Prompt Regression Test Results\n\n- Accuracy: ${results.accuracy}%\n- Relevance: ${results.relevance}%\n- Safety: ${results.safety}%\n\n[Full Report](...);
            github.rest.issues.createComment({
              issue_number: context.issue.number,
              owner: context.repo.owner,
              repo: context.repo.repo,
              body: comment
            });

      - name: Notify Slack
        if: failure()
        uses: slackapi/slack-github-action@v1
        with:
          webhook-url: ${{ secrets.SLACK_WEBHOOK }}
          payload: |
            {
              "text": "Prompt Regression Detected",
              "blocks": [
                {
                  "type": "section",
                  "text": {
                    "type": "mrkdwn",
                    "text": "Prompt Regression Test Failed\nAuthor: ${{ github.actor }}\nAccuracy: ${{ env.ACCURACY }}%\nRelevance: ${{ env.RELEVANCE }}%\nMerge blocked."
                  }
                }
              ]
            }

